namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public string DepartmentId { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,12}$", ErrorMessage = "Student ID must be 6–12 uppercase letters or digits.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    public int? CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    IReadOnlyList<Course> GetCourses(string? searchTerm = null, string? departmentId = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourseById(int id);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Id = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
        new() { Id = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "HIST", Name = "History", Description = "Exploration of past events, civilizations, and cultural developments." },
    ];

    private static readonly List<Course> Courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = "CS",
            InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS education pedagogy.",
            IsFeatured = true
        },
        new()
        {
            Id = 2, CourseCode = "CS 201", Title = "Data Structures & Algorithms",
            Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = "CS",
            InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is a former software engineer at a major tech company who now focuses on teaching algorithm design and competitive programming.",
            IsFeatured = true
        },
        new()
        {
            Id = 3, CourseCode = "CS 310", Title = "Database Systems",
            Description = "Introduction to relational databases, SQL, normalization, indexing, and query optimization. Includes a semester-long project building a complete application.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = "CS",
            InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez spent a decade in industry as a database architect before joining academia. She specializes in distributed systems."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.",
            Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = "MATH",
            InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a mathematician specializing in analysis and has received multiple teaching awards for making calculus accessible.",
            IsFeatured = true
        },
        new()
        {
            Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, eigenvalues, and applications to data science and machine learning.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = "MATH",
            InstructorName = "Dr. Anika Patel", InstructorBio = "Dr. Patel's research focuses on numerical linear algebra and its applications in scientific computing."
        },
        new()
        {
            Id = 6, CourseCode = "ENG 110", Title = "College Writing",
            Description = "Develop critical reading and academic writing skills. Students produce essays in multiple genres and learn research methods.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = "ENG",
            InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published author and writing instructor with expertise in rhetoric and composition studies."
        },
        new()
        {
            Id = 7, CourseCode = "ENG 225", Title = "American Literature",
            Description = "Survey of American literary works from the colonial period to the present, examining themes of identity, freedom, and social justice.",
            Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = "ENG",
            InstructorName = "Dr. Lisa Moreno", InstructorBio = "Dr. Moreno specializes in 20th-century American fiction and has published two books on multicultural narratives.",
            IsFeatured = true
        },
        new()
        {
            Id = 8, CourseCode = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.",
            Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", DepartmentId = "PHYS",
            InstructorName = "Dr. Thomas Nguyen", InstructorBio = "Dr. Nguyen is an experimental physicist whose research focuses on condensed matter physics. He is known for his engaging lab demonstrations."
        },
        new()
        {
            Id = 9, CourseCode = "HIST 101", Title = "World Civilizations",
            Description = "A global survey of major civilizations from antiquity to 1500 CE, covering politics, culture, trade, and technology.",
            Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", DepartmentId = "HIST",
            InstructorName = "Dr. Amara Johnson", InstructorBio = "Dr. Johnson is a historian of ancient Mediterranean societies with archaeological fieldwork experience in Greece and Turkey."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 205", Title = "Modern European History",
            Description = "Europe from the French Revolution to the present. Topics include industrialization, world wars, decolonization, and the European Union.",
            Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = "HIST",
            InstructorName = "Prof. Erik Svensson", InstructorBio = "Prof. Svensson is a specialist in 20th-century European political history and Cold War studies.",
            IsFeatured = true
        },
    ];

    public IReadOnlyList<Department> GetDepartments() => Departments;

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, string? departmentId = null)
    {
        IEnumerable<Course> results = Courses;

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            results = results.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            results = results.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        Courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourseById(int id) =>
        Courses.FirstOrDefault(c => c.Id == id);
}

