@page "/courses"
@inject UniversityCourseCatalog.Services.ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search"
               placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, Department);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentId</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-secondary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public string? Department { get; set; }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
            <strong>@(CatalogService.GetCourseById(Model.CourseId!.Value)?.Title ?? "the selected course")</strong>
            has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation email at your university address within 2 business days.</p>
    </div>
    <a href="courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    <form method="post" class="needs-validation" style="max-width: 600px;">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="fullName" name="Model.FullName"
                   value="@Model.FullName" required maxlength="100" />
            @if (errors.ContainsKey(nameof(Model.FullName)))
            {
                <div class="text-danger small mt-1">@errors[nameof(Model.FullName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" required placeholder="e.g. STU12345"
                   pattern="[A-Z0-9]{6,12}" />
            <div class="form-text">6–12 uppercase letters or digits.</div>
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <div class="text-danger small mt-1">@errors[nameof(Model.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="">— Select a course —</option>
                @foreach (var course in CatalogService.GetCourses())
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                        @course.CourseCode — @course.Title
                    </option>
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <div class="text-danger small mt-1">@errors[nameof(Model.CourseId)]</div>
            }
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }
    private Dictionary<string, string> errors = new();

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        // Validate on POST
        if (HttpContextAccessor is not null) return;
    }

    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    protected override void OnAfterRender(bool firstRender) { }

    public void OnPost()
    {
        // This method is not directly called - validation is handled below
    }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId.Value;
        }
    }
}

